import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How much do you need to retire?", a: "A common starting point is the 4% rule, which estimates that you may need about 25 times your annual retirement spending. Your real target can change based on age, lifestyle, market returns, taxes, and inflation." },
  { q: "What is the 4% rule in retirement?", a: "The 4% rule estimates retirement income by withdrawing 4% of your savings in the first year of retirement, then adjusting withdrawals for inflation. It is a planning guideline, not a guarantee." },
  { q: "How does inflation affect retirement savings?", a: "Inflation reduces purchasing power over time. This calculator shows an inflation-adjusted value so you can see what your projected savings may be worth in today's dollars." },
  { q: "When should you start saving for retirement?", a: "Starting earlier gives compound growth more time to work. Even small monthly contributions can grow substantially when invested consistently over many years." },
  { q: "What is the difference between a 401k and an IRA?", a: "A 401k is typically offered through an employer, while an IRA is opened individually. Both can provide tax advantages, but contribution limits, eligibility rules, and investment options differ." },
];

const money = (value: number, digits = 0) => formatCurrencyValue(value, { maximumFractionDigits: digits });

function futureValue(currentSavings: number, monthlyContribution: number, annualReturn: number, years: number) {
  const months = Math.max(0, Math.round(years * 12));
  const monthlyReturn = annualReturn / 100 / 12;
  const currentGrowth = currentSavings * Math.pow(1 + monthlyReturn, months);
  const contributionGrowth = monthlyReturn === 0
    ? monthlyContribution * months
    : monthlyContribution * ((Math.pow(1 + monthlyReturn, months) - 1) / monthlyReturn);
  return currentGrowth + contributionGrowth;
}

export default function RetirementCalculator() {
  useCurrencyVersion();
  const [currentAge, setCurrentAge] = useState(30);
  const [retirementAge, setRetirementAge] = useState(65);
  const [currentSavings, setCurrentSavings] = useState(25000);
  const [monthlyContribution, setMonthlyContribution] = useState(500);
  const [annualReturn, setAnnualReturn] = useState(7);
  const [inflationRate, setInflationRate] = useState(3);
  const [desiredMonthlyIncome, setDesiredMonthlyIncome] = useState(4000);

  const yearsToRetirement = Math.max(0, retirementAge - currentAge);
  const projectedSavings = futureValue(currentSavings, monthlyContribution, annualReturn, yearsToRetirement);
  const inflationAdjustedValue = projectedSavings / Math.pow(1 + inflationRate / 100, yearsToRetirement || 0);
  const monthlyRetirementIncome = projectedSavings * 0.04 / 12;
  const retirementGoal = desiredMonthlyIncome * 12 * 25;
  const onTrack = projectedSavings >= retirementGoal;
  const gap = Math.max(0, retirementGoal - projectedSavings);

  const yearlyRows = Array.from({ length: yearsToRetirement + 1 }, (_, index) => {
    const age = currentAge + index;
    const balance = futureValue(currentSavings, monthlyContribution, annualReturn, index);
    const adjusted = balance / Math.pow(1 + inflationRate / 100, index || 0);
    return { age, year: index, balance, adjusted };
  });

  const comparisonRows = [100, 250, 500, 1000, 2000].map((contribution) => ({
    contribution,
    y10: futureValue(0, contribution, 7, 10),
    y20: futureValue(0, contribution, 7, 20),
    y30: futureValue(0, contribution, 7, 30),
    y40: futureValue(0, contribution, 7, 40),
  }));

  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  return (
    <>
      <SEOHead
        title="Free Retirement Calculator Online - Calculate How Much You Need to Retire Instantly | CalcHive"
        description="Free online retirement calculator. Calculate your retirement savings, monthly retirement income and whether you are on track to retire comfortably. 100% free, no signup required."
        canonical="/retirement-calculator"
        keywords="free retirement calculator, retirement savings calculator free online, how much do I need to retire calculator free, retirement planning calculator free, 401k retirement calculator free"
        category="Financial Calculators"
        breadcrumbName="Free Retirement Calculator Online"
        schemaType="WebApplication"
        schemaApplicationCategory="CalculatorApplication"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Retirement Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free retirement calculator to estimate your retirement savings, monthly retirement income, and whether you are on track for your goal.</p>
        </div>

        <AdPlaceholder size="banner" className="mb-8" />

        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">Current age</label>
              <input type="number" min="0" value={currentAge} onChange={(event) => setCurrentAge(Number(event.target.value))} className={inputClass} />
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">Retirement age</label>
              <input type="number" min="1" value={retirementAge} onChange={(event) => setRetirementAge(Number(event.target.value))} className={inputClass} />
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">Current savings</label>
              <input type="number" min="0" value={currentSavings} onChange={(event) => setCurrentSavings(Number(event.target.value))} className={inputClass} />
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">Monthly contribution</label>
              <input type="number" min="0" value={monthlyContribution} onChange={(event) => setMonthlyContribution(Number(event.target.value))} className={inputClass} />
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">Expected annual return (%)</label>
              <input type="number" min="0" step="0.1" value={annualReturn} onChange={(event) => setAnnualReturn(Number(event.target.value))} className={inputClass} />
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">Expected inflation rate (%)</label>
              <input type="number" min="0" step="0.1" value={inflationRate} onChange={(event) => setInflationRate(Number(event.target.value))} className={inputClass} />
            </div>
            <div className="sm:col-span-2">
              <label className="text-sm font-semibold text-foreground block mb-2">Desired monthly retirement income</label>
              <input type="number" min="0" value={desiredMonthlyIncome} onChange={(event) => setDesiredMonthlyIncome(Number(event.target.value))} className={inputClass} />
            </div>
          </div>

          <motion.div key={`${currentAge}-${retirementAge}-${currentSavings}-${monthlyContribution}-${annualReturn}-${inflationRate}-${desiredMonthlyIncome}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${onTrack ? "from-emerald-500 to-emerald-700" : "from-sky-500 to-sky-700"} rounded-2xl p-6 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Savings at Retirement</p>
              <p className="text-5xl sm:text-6xl font-black text-white tracking-tight" data-testid="result-retirement">{money(projectedSavings)}</p>
              <p className="text-white/75 text-sm mt-2">{onTrack ? "You are on track for this retirement income goal." : `${money(gap)} more needed to meet this goal.`}</p>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">
              {[
                ["Monthly retirement income", money(monthlyRetirementIncome)],
                ["Inflation-adjusted value", money(inflationAdjustedValue)],
                ["Savings goal", money(retirementGoal)],
              ].map(([label, value]) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>

        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate How Much You Need to Retire for Free</h2>
          <p className="text-muted-foreground leading-relaxed">This retirement savings calculator free online projects current savings and monthly contributions forward to retirement, then compares the result with a goal based on the 4% rule.</p>

          <h2 className="text-2xl font-bold text-foreground">How Monthly Contributions and Returns Grow Your Retirement Savings</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <caption className="caption-top text-left font-bold text-foreground mb-3">Retirement Savings by Monthly Contribution at 7% Return</caption>
              <thead className="bg-muted/60">
                <tr>{["Monthly Contribution", "10 Years", "20 Years", "30 Years", "40 Years"].map((heading) => <th key={heading} className="text-left py-3 px-3 font-semibold text-foreground">{heading}</th>)}</tr>
              </thead>
              <tbody className="divide-y divide-border">
                {comparisonRows.map((row) => (
                  <tr key={row.contribution} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{money(row.contribution)}</td>
                    <td className="py-2.5 px-3">{money(row.y10)}</td>
                    <td className="py-2.5 px-3">{money(row.y20)}</td>
                    <td className="py-2.5 px-3">{money(row.y30)}</td>
                    <td className="py-2.5 px-3">{money(row.y40)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Retirement Planning Tool for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <caption className="caption-top text-left font-bold text-foreground mb-3">Year by Year Savings Growth</caption>
              <thead className="bg-muted/60">
                <tr>{["Year", "Age", "Projected Savings", "Inflation-Adjusted Value"].map((heading) => <th key={heading} className="text-left py-3 px-3 font-semibold text-foreground">{heading}</th>)}</tr>
              </thead>
              <tbody className="divide-y divide-border">
                {yearlyRows.map((row) => (
                  <tr key={row.year} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{row.year}</td>
                    <td className="py-2.5 px-3">{row.age}</td>
                    <td className="py-2.5 px-3 text-sky-600 dark:text-sky-400 font-semibold">{money(row.balance)}</td>
                    <td className="py-2.5 px-3">{money(row.adjusted)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div>
        </section>

        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/retirement-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


